import React, { useState } from 'react';
import { FileText, Book, Gavel, ArrowRight, ScrollText, ArrowLeft, Check } from 'lucide-react';

// MultiSectionForm Component
const MultiSectionForm = () => {
  const [currentSection, setCurrentSection] = useState(0);
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    caseTitle: '',
    caseNumber: '',
    jurisdiction: '',
    filingType: '',
    urgencyLevel: '',
    comments: ''
  });

  const sections = [
    {
      title: 'Personal Information',
      description: 'Please provide your contact details'
    },
    {
      title: 'Case Information',
      description: 'Enter the details about your case'
    },
    {
      title: 'Additional Details',
      description: 'Any other relevant information'
    }
  ];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleNextSection = () => {
    if (currentSection < sections.length - 1) {
      setCurrentSection(prev => prev + 1);
    }
  };

  const handlePreviousSection = () => {
    if (currentSection > 0) {
      setCurrentSection(prev => prev - 1);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Form submitted:', formData);
  };

  const renderCurrentSection = () => {
    switch (currentSection) {
      case 0:
        return (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
                  First Name
                </label>
                <input
                  type="text"
                  name="firstName"
                  value={formData.firstName}
                  onChange={handleChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
                  Last Name
                </label>
                <input
                  type="text"
                  name="lastName"
                  value={formData.lastName}
                  onChange={handleChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
                  Email
                </label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
                  Phone
                </label>
                <input
                  type="tel"
                  name="phone"
                  value={formData.phone}
                  onChange={handleChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>
            </div>
          </div>
        );
      case 1:
        return (
          <div className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
                Case Title
              </label>
              <input
                type="text"
                name="caseTitle"
                value={formData.caseTitle}
                onChange={handleChange}
                className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
                Case Number
              </label>
              <input
                type="text"
                name="caseNumber"
                value={formData.caseNumber}
                onChange={handleChange}
                className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
                Jurisdiction
              </label>
              <input
                type="text"
                name="jurisdiction"
                value={formData.jurisdiction}
                onChange={handleChange}
                className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
                Filing Type
              </label>
              <select
                name="filingType"
                value={formData.filingType}
                onChange={handleChange}
                className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="">Select Filing Type</option>
                <option value="motion">Motion</option>
                <option value="petition">Petition</option>
                <option value="complaint">Complaint</option>
                <option value="response">Response</option>
              </select>
            </div>
          </div>
        );
      case 2:
        return (
          <div className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
                Urgency Level
              </label>
              <select
                name="urgencyLevel"
                value={formData.urgencyLevel}
                onChange={handleChange}
                className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="">Select Urgency</option>
                <option value="low">Low</option>
                <option value="medium">Medium</option>
                <option value="high">High</option>
                <option value="urgent">Urgent</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-200 mb-1">
                Additional Comments
              </label>
              <textarea
                name="comments"
                value={formData.comments}
                onChange={handleChange}
                rows="3"
                className="w-full px-3 py-2 border border-gray-300 rounded-md dark:border-gray-600 dark:bg-gray-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="max-w-4xl mx-auto bg-white dark:bg-gray-800 rounded-lg shadow-lg">
      <div className="mb-8">
        <div className="flex justify-between mb-2">
          {sections.map((section, index) => (
            <div
              key={index}
              className={`flex-1 text-center ${
                index === currentSection
                  ? 'text-blue-600 dark:text-blue-400'
                  : 'text-gray-500'
              }`}
            >
              <span className="text-sm font-medium">{section.title}</span>
            </div>
          ))}
        </div>
        <div className="relative">
          <div className="absolute top-0 h-2 bg-gray-200 dark:bg-gray-700 w-full rounded-full">
            <div
              className="h-2 bg-blue-600 rounded-full transition-all duration-300"
              style={{ width: `${((currentSection + 1) / sections.length) * 100}%` }}
            />
          </div>
        </div>
      </div>

      <div className="p-6">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">
          {sections[currentSection].title}
        </h2>
        <p className="text-gray-600 dark:text-gray-400 mb-6">
          {sections[currentSection].description}
        </p>
        <form onSubmit={handleSubmit}>
          {renderCurrentSection()}
        </form>
      </div>

      <div className="flex justify-between p-6 border-t border-gray-200 dark:border-gray-700">
        <button
          type="button"
          onClick={handlePreviousSection}
          disabled={currentSection === 0}
          className={`flex items-center px-4 py-2 rounded-md ${
            currentSection === 0
              ? 'text-gray-400 cursor-not-allowed'
              : 'text-gray-600 hover:text-gray-900 dark:text-gray-400 dark:hover:text-white'
          }`}
        >
          <ArrowLeft className="h-4 w-4 mr-2" />
          Previous
        </button>
        
        {currentSection === sections.length - 1 ? (
          <button
            type="submit"
            onClick={handleSubmit}
            className="flex items-center px-6 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2"
          >
            <Check className="h-4 w-4 mr-2" />
            Submit
          </button>
        ) : (
          <button
            type="button"
            onClick={handleNextSection}
            className="flex items-center px-6 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2"
          >
            Next
            <ArrowRight className="h-4 w-4 ml-2" />
          </button>
        )}
      </div>
    </div>
  );
};

// Form Card Component
const FormCard = ({ title, description, icon: Icon, active, disabled, bgColor }) => {
  return (
    <div
      className={`relative overflow-hidden rounded-2xl transition-all duration-300
        ${disabled ? 'opacity-75' : 'hover:shadow-2xl'}
        ${active ? 'ring-2 ring-blue-500 shadow-lg' : ''}
      `}
    >
      <div className={`absolute inset-0 bg-gradient-to-br ${bgColor} opacity-10`} />
      
      <div className="relative p-8 bg-white dark:bg-gray-800 h-full">
        <div className="flex flex-col h-full">
          <div className="flex-shrink-0">
            <div className="inline-flex items-center justify-center h-12 w-12 rounded-xl bg-blue-100 dark:bg-blue-900 mb-4">
              <Icon className="h-6 w-6 text-blue-600 dark:text-blue-400" />
            </div>
          </div>
          
          <h3 className="text-xl font-semibold text-gray-900 dark:text-white mb-2">
            {title}
          </h3>
          
          <p className="text-gray-500 dark:text-gray-400 mb-4 flex-grow">
            {description}
          </p>
          
          {!disabled ? (
            <button className="inline-flex items-center text-blue-600 hover:text-blue-700 font-medium">
              Access form
              <ArrowRight className="ml-2 h-4 w-4" />
            </button>
          ) : (
            <span className="inline-flex items-center text-gray-400 font-medium">
              Coming Soon
            </span>
          )}
        </div>
      </div>
    </div>
  );
};

// Stats and Form Cards Data
const stats = [
  {
    label: "Documents Processed",
    value: "10,000+",
    icon: ScrollText
  },
  {
    label: "Success Rate",
    value: "99.9%",
    icon: Gavel
  },
  {
    label: "Available Templates",
    value: "50+",
    icon: Book
  }
];

const formCards = [
  {
    title: "Document Filing",
    description: "Submit new legal documents and filings with our intelligent form system",
    icon: FileText,
    active: true,
    disabled: false,
    bgColor: "from-blue-500 to-blue-600"
  },
  {
    title: "Motion Templates",
    description: "Access and fill standardized motion forms pre-approved by the court",
    icon: ScrollText,
    active: false,
    disabled: true,
    bgColor: "from-purple-500 to-purple-600"
  },
  {
    title: "Court Submissions",
    description: "Submit documents directly to court with automatic validation",
    icon: Gavel,
    active: false,
    disabled: true,
    bgColor: "from-green-500 to-green-600"
  }
];

// Main FormsPage Component
const FormsPage = () => {
    return (
      <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 dark:from-gray-900 dark:to-gray-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
          <div className="text-center mb-16">
            <h1 className="text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-blue-400 mb-4">
              Legal Document Portal
            </h1>
            <p className="text-lg text-gray-600 dark:text-gray-300 max-w-2xl mx-auto">
              Streamline your legal document workflow with our intelligent forms system.
              Complete and submit documents with confidence.
            </p>
          </div>
  
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
            {stats.map((stat, index) => (
              <div 
                key={index}
                className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg transform hover:scale-105 transition-all duration-300"
              >
                <div className="flex items-center space-x-4">
                  <div className="p-3 bg-blue-100 dark:bg-blue-900 rounded-lg">
                    <stat.icon className="h-6 w-6 text-blue-600 dark:text-blue-400" />
                  </div>
                  <div>
                    <p className="text-2xl font-bold text-gray-900 dark:text-white">{stat.value}</p>
                    <p className="text-sm text-gray-500 dark:text-gray-400">{stat.label}</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
  
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
            {formCards.map((card, index) => (
              <FormCard
                key={index}
                {...card}
                className="transform hover:-translate-y-1 transition-all duration-300"
              />
            ))}
          </div>
  
          <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-xl p-8">
            <MultiSectionForm />
          </div>
        </div>
      </div>
    );
  };
  
  export default FormsPage;
